if (!(Test-Path $batchDir)) { New-Item -ItemType Directory -Path $batchDir -Force | Out-Null }

# =====================================================================
# 1. DEI VOCABULARY
# =====================================================================

$dei = @(
@{word="Diversity";meaning="The presence of a wide variety of human differences, such as race, gender, age, and background, within a group or organization.";example="The university boasts a rich diversity of students from over fifty different countries.";category="DEI Core Concepts"},
@{word="Equity";meaning="The practice of ensuring everyone has access to the same opportunities by recognizing that different people have different needs.";example="By providing extra tutoring to students who were struggling, the school demonstrated its commitment to equity.";category="DEI Core Concepts"},
@{word="Inclusion";meaning="The act of creating an environment where all individuals feel welcomed, respected, supported, and valued.";example="The company's new policy focuses on inclusion, making sure every employee's voice is heard during meetings.";category="DEI Core Concepts"},
@{word="Social Justice";meaning="The view that everyone deserves equal economic, political, and social rights and opportunities.";example="Many young people are actively involved in campaigns that fight for social justice and human rights.";category="DEI Core Concepts"},
@{word="Privilege";meaning="A special advantage or benefit that a person has because of their social group, identity, or background, often without realizing it.";example="Growing up in a wealthy neighborhood is a privilege that provides better access to high-quality education.";category="DEI Core Concepts"},
@{word="Intersectionality";meaning="The concept of how different parts of a person's identity (like race, gender, and class) combine to create unique experiences of discrimination or privilege.";example="Her research on intersectionality explores how race and gender together affect a woman's career path.";category="DEI Core Concepts"},
@{word="Marginalization";meaning="The process of pushing a particular group of people to the edge of society, giving them less power and importance.";example="For centuries, minor groups faced marginalization, being excluded from political decision-making.";category="DEI Core Concepts"},
@{word="Bias";meaning="A personal and sometimes unreasonable preference for or dislike of a person, group, or idea, which influences decision-making.";example="The judge was accused of bias because he had a personal relationship with the defendant.";category="DEI Core Concepts"},
@{word="Prejudice";meaning="An unfair or unreasonable opinion or feeling formed about someone before knowing them, often based on their group identity.";example="To build a harmonious community, we must work together to overcome racial prejudice.";category="DEI Core Concepts"},
@{word="Discrimination";meaning="The unfair or prejudicial treatment of different categories of people, especially on the grounds of race, age, or sex.";example="It is illegal to practice discrimination against job applicants based on their age or religion.";category="DEI Core Concepts"},
@{word="Systemic Barriers";meaning="Rules, practices, or cultures in an institution that show favoritism toward one group and create disadvantages for another.";example="The organization is working to remove systemic barriers that prevent low-income students from attending college.";category="DEI Core Concepts"},
@{word="Belonging";meaning="The feeling of being accepted, secure, and supported within a community, school, or workplace.";example="Participating in team-building activities helped the new hire develop a strong sense of belonging.";category="DEI Core Concepts"},
@{word="Psychological Safety";meaning="An environment where people feel comfortable sharing ideas, asking questions, and making mistakes without fear of negative consequences.";example="A high level of psychological safety allows developers to admit coding errors without fear of blame.";category="DEI Core Concepts"},
@{word="Allyship";meaning="A continuous process of learning and acting to support marginalized groups, using one's influence or privilege to advocate for them.";example="Active allyship involves speaking up when a colleague is treated unfairly or excluded from discussions.";category="DEI Core Concepts"},
@{word="Advocacy";meaning="The public support for or recommendation of a particular cause, policy, or group of people.";example="The non-profit organization is known for its strong advocacy of environmental protection and clean energy.";category="DEI Core Concepts"},
@{word="Diversity Dimensions";meaning="The various aspects of human identity, such as race, ethnicity, gender, sexual orientation, age, physical ability, and religion.";example="Understanding different diversity dimensions helps the human resources team build a more balanced workforce.";category="DEI Core Concepts"},
@{word="Equal Opportunity";meaning="The principle of treating everyone equally and fairly, without discrimination, in employment, education, and public services.";example="Our company is an equal opportunity employer, welcoming applications from all qualified individuals.";category="DEI Core Concepts"},
@{word="Human Rights";meaning="The basic rights and freedoms that belong to every person in the world, from birth until death.";example="Ensuring access to clean water, food, and education is a fundamental matter of human rights.";category="DEI Core Concepts"},
@{word="Underrepresented";meaning="A term describing a group of people who are not present in a particular field, company, or institution in proportion to their population.";example="Women remain underrepresented in senior leadership roles within the technology sector.";category="DEI Core Concepts"},
@{word="Inherent Worth";meaning="The belief that every human being has value and deserves respect simply because they exist, regardless of their background or abilities.";example="The core principle of our organization is that every individual possesses inherent worth and deserves dignity.";category="DEI Core Concepts"},
@{word="Social Integration";meaning="The process through which diverse individuals or groups are welcomed and incorporated into a unified, harmonious society.";example="Language classes play a crucial role in the social integration of new immigrants into the local community.";category="DEI Core Concepts"},
@{word="Cultural Diversity";meaning="The existence of a variety of cultural or ethnic groups within a society or organization.";example="The city's cultural diversity is celebrated annually through a vibrant food and music festival.";category="DEI Core Concepts"},
@{word="Pluralism";meaning="A system in which two or more states, groups, or principles coexist peacefully and maintain their unique identities.";example="Democratic societies thrive on pluralism, where different religious and political groups coexist peacefully.";category="DEI Core Concepts"},
@{word="Empowerment";meaning="The process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights.";example="Providing microloans to female entrepreneurs is a powerful tool for economic empowerment.";category="DEI Core Concepts"},
@{word="Shared Humanity";meaning="The recognition of the basic common qualities, feelings, and rights that connect all human beings across different cultures.";example="During global crises, acts of kindness remind us of our shared humanity across borders.";category="DEI Core Concepts"},
@{word="Tolerance";meaning="The ability or willingness to tolerate the existence of opinions or behavior that one dislikes or disagrees with.";example="Religious tolerance is essential for maintaining peace and harmony in a multi-cultural nation.";category="DEI Core Concepts"},
@{word="Respect";meaning="A feeling of deep admiration for someone or something, elicited by their abilities, qualities, achievements, or human dignity.";example="In any professional debate, it is important to treat your opponents with respect and courtesy.";category="DEI Core Concepts"},
@{word="Dignity";meaning="The state or quality of being worthy of honor or respect, which every person is entitled to.";example="Every patient in the hospital has the right to be treated with dignity and care.";category="DEI Core Concepts"},
@{word="Social Consciousness";meaning="The state of being aware of the problems and injustices that affect individuals and communities in society.";example="Documentaries can raise social consciousness about important issues like poverty and climate change.";category="DEI Core Concepts"},
@{word="Common Good";meaning="The advantage or benefit of all members of a society or community.";example="Sometimes, individuals must make small sacrifices for the common good of the entire neighborhood.";category="DEI Core Concepts"},
@{word="Unconscious Bias";meaning="Social stereotypes about certain groups of people that individuals form outside their own conscious awareness.";example="Recruiters underwent training to recognize and minimize unconscious bias during the hiring process.";category="Workplace Inclusivity"},
@{word="Microaggression";meaning="A subtle, often unintentional comment or action that expresses a prejudiced attitude toward a marginalized group.";example="Asking a colleague 'Where are you really from?' is a common example of a microaggression.";category="Workplace Inclusivity"},
@{word="Inclusive Leadership";meaning="A style of leadership where managers actively seek out and value different perspectives to make better, fairer decisions.";example="Through inclusive leadership, the director ensured that junior developers could contribute to key decisions.";category="Workplace Inclusivity"},
@{word="Affirmative Action";meaning="Policies or practices designed to actively support and hire individuals from historically disadvantaged groups.";example="The university's affirmative action policy helped increase enrollment of students from minority backgrounds.";category="Workplace Inclusivity"},
@{word="Reasonable Accommodation";meaning="Modifications or adjustments made to a job or work environment that enable an employee with a disability to perform their duties.";example="Installing a ramp at the office entrance is a reasonable accommodation for employees who use wheelchairs.";category="Workplace Inclusivity"},
@{word="Neurodiversity";meaning="The concept that differences in human brain function (such as ADHD, autism, or dyslexia) are normal variations rather than illnesses.";example="By embracing neurodiversity, the company found that autistic employees brought unique strengths to data analysis.";category="Workplace Inclusivity"},
@{word="Cultural Fit";meaning="A traditional hiring practice where candidates are chosen based on how well they match the existing workplace culture, which can sometimes lead to a lack of diversity.";example="Relying too much on cultural fit can lead managers to hire people who look and think exactly like them.";category="Workplace Inclusivity"},
@{word="Cultural Add";meaning="The practice of hiring people who bring new perspectives, backgrounds, and values to a company rather than just matching existing ones.";example="Instead of looking for a cultural fit, the startup prioritized cultural add to bring in fresh ideas.";category="Workplace Inclusivity"},
@{word="Gender Pronouns";meaning="The words (such as he/him, she/her, they/them) that a person chooses to represent their gender identity.";example="Many employees include their gender pronouns in their email signatures to promote an inclusive environment.";category="Workplace Inclusivity"},
@{word="Tokenism";meaning="The practice of doing something (such as hiring one person from a minority group) only to prevent criticism and give the appearance of fairness.";example="Putting a single minority employee on every brochure cover can be perceived as insincere tokenism.";category="Workplace Inclusivity"},
@{word="Code-switching";meaning="The act of adjusting one's style of speech, appearance, or behavior to conform to different cultural norms or workplace expectations.";example="She described the exhaustion of code-switching between her home dialect and the formal language of the office.";category="Workplace Inclusivity"},
@{word="Employee Resource Group";meaning="A voluntary, employee-led group formed around shared characteristics or life experiences to foster a diverse and inclusive workplace.";example="The LGBTQ+ Employee Resource Group organized a series of educational workshops during Pride Month.";category="Workplace Inclusivity"},
@{word="Safe Space";meaning="A supportive, non-threatening environment where people can feel free to express themselves without fear of discrimination, judgment, or harassment.";example="The support group provided a safe space for parents to share their challenges without feeling judged.";category="Workplace Inclusivity"},
@{word="Inclusive Language";meaning="Language that avoids words or phrases that could exclude, offend, or stereotype particular groups of people.";example="Using 'spouses' instead of 'husbands and wives' is an easy way to practice inclusive language.";category="Workplace Inclusivity"},
@{word="Glass Ceiling";meaning="An invisible barrier that prevents women and minority groups from rising to top-level positions in a company or organization.";example="By becoming the first female CEO of the bank, she successfully shattered the glass ceiling.";category="Workplace Inclusivity"},
@{word="Wage Gap";meaning="The difference in average pay between different groups of employees, such as men and women or different racial groups, performing similar work.";example="The government introduced new transparency laws aimed at closing the gender wage gap.";category="Workplace Inclusivity"},
@{word="Micro-validation";meaning="A subtle, small gesture or comment that affirms and supports someone's value, ideas, or identity in a group setting.";example="Nodding and acknowledging a colleague's point during a heated debate is a form of micro-validation.";category="Workplace Inclusivity"},
@{word="Equity Audit";meaning="A systematic review of a company's policies, pay, and practices to identify and eliminate unfair treatment and systemic bias.";example="The equity audit revealed that male employees were promoted faster than their female counterparts.";category="Workplace Inclusivity"},
@{word="Accessibility";meaning="The quality of being easy to approach, enter, speak with, use, or understand, especially for people with disabilities.";example="Adding closed captions to training videos improves accessibility for employees with hearing impairments.";category="Workplace Inclusivity"},
@{word="Universal Design";meaning="The design of buildings, products, or environments to make them accessible and usable by all people, regardless of age, size, or ability.";example="The new headquarters was built using universal design, featuring automatic doors and height-adjustable desks.";category="Workplace Inclusivity"},
@{word="Micro-affirmation";meaning="A small, subtle action or comment that helps someone feel valued, included, and respected in the workplace.";example="A simple micro-affirmation, like saying 'that is a great question,' can boost a new employee's confidence.";category="Workplace Inclusivity"},
@{word="Bias Interrupter";meaning="A practical policy or action used in the workplace to stop bias before it influences hiring, promotions, or performance reviews.";example="Removing names from resumes before reviewing them is an effective bias interrupter in recruitment.";category="Workplace Inclusivity"},
@{word="Meritocracy";meaning="A system or organization where people are chosen and promoted based on their talent and effort, which can sometimes fail if systemic barriers are ignored.";example="While a meritocracy sounds fair, it only works if every candidate starts with the same resources and opportunities.";category="Workplace Inclusivity"},
@{word="Equal Pay for Equal Work";meaning="The principle that men and women in the same workplace should receive equal pay for performing equal work.";example="The union fought to guarantee equal pay for equal work across all manufacturing plants.";category="Workplace Inclusivity"},
@{word="Active Ally";meaning="A person in the workplace who actively uses their power, privilege, or voice to support and defend colleagues from marginalized groups.";example="As an active ally, he stood up and corrected a client who made a sexist comment during the meeting.";category="Workplace Inclusivity"},
@{word="Inclusive Hiring";meaning="The practice of designing recruitment processes that attract a diverse pool of candidates and eliminate unfair bias in selection.";example="The HR department updated their job descriptions to ensure they followed inclusive hiring practices.";category="Workplace Inclusivity"},
@{word="Cultural Competency Training";meaning="Educational programs designed to help employees understand, respect, and work effectively with people from different cultural backgrounds.";example="All customer service agents complete cultural competency training to better serve international clients.";category="Workplace Inclusivity"},
@{word="Mentorship Loop";meaning="A formal arrangement where experienced employees provide guidance and career support to newer, diverse team members.";example="The company's mentorship loop pairs senior executives with junior employees from underrepresented groups.";category="Workplace Inclusivity"},
@{word="Sponsorship";meaning="A relationship where a senior leader actively uses their influence and authority to help advance the career of a junior colleague.";example="Thanks to the sponsorship of the vice president, the talented manager was recommended for a promotion.";category="Workplace Inclusivity"},
@{word="Structural Equity";meaning="The design of organizational systems, such as pay bands and promotion tracks, to ensure fairness and equal opportunity for all.";example="The board established structural equity by standardizing salary ranges for all department heads.";category="Workplace Inclusivity"},
@{word="Systemic Racism";meaning="Policies and practices within institutions (such as schools, banks, or courts) that result in and support unfair treatment of some racial groups.";example="Redlining in housing policies is a clear historical example of systemic racism that still affects wealth today.";category="Social Justice & Equity"},
@{word="Institutional Bias";meaning="Unfair practices and policies embedded within an organization that systematically favor one group over another.";example="The standardized test was criticized for institutional bias because it favored students from wealthy schools.";category="Social Justice & Equity"},
@{word="Disenfranchisement";meaning="The state of being deprived of a right or privilege, especially the right to vote or participate fully in society.";example="Strict voting laws can lead to the disenfranchisement of low-income citizens who lack official identification.";category="Social Justice & Equity"},
@{word="Reparations";meaning="Actions or payments made to make amends or provide compensation for historical injustices and systemic harm.";example="Historians debated the most effective way to distribute reparations to descendants of enslaved people.";category="Social Justice & Equity"},
@{word="Decolonization";meaning="The process of uncovering and dismantling colonial ideologies, structures, and practices in education, culture, and governance.";example="The university department began a process of decolonization by adding African and Asian authors to the syllabus.";category="Social Justice & Equity"},
@{word="Restorative Justice";meaning="An approach to justice that focuses on repairing the harm caused by behavior through cooperative processes and healing rather than punishment.";example="The school used restorative justice, allowing the student to apologize and repair the damage instead of being suspended.";category="Social Justice & Equity"},
@{word="Social Equity";meaning="The active commitment to fairness, justice, and equality in the formulation of public policy and distribution of social resources.";example="The city council's housing policy promotes social equity by reserving twenty percent of new apartments for low-income families.";category="Social Justice & Equity"},
@{word="Underserved Communities";meaning="Populations that have limited access to essential services, resources, and opportunities due to geographic, social, or economic barriers.";example="Mobile clinics were launched to provide basic healthcare to underserved communities in rural areas.";category="Social Justice & Equity"},
@{word="Socioeconomic Status";meaning="The social standing or class of an individual or group, often measured as a combination of education, income, and occupation.";example="Students from low socioeconomic status often face challenges in accessing high-quality test prep materials.";category="Social Justice & Equity"},
@{word="Ableism";meaning="The unfair treatment, prejudice, or discrimination against people with physical or mental disabilities.";example="Assuming that a person in a wheelchair cannot do a desk job is a common form of ableism.";category="Social Justice & Equity"},
@{word="Ageism";meaning="The unfair treatment, stereotyping, or discrimination against individuals based on their age, especially elderly or younger people.";example="Rejecting a highly qualified candidate because they are 'too close to retirement' is an example of ageism.";category="Social Justice & Equity"},
@{word="Xenophobia";meaning="The fear, hatred, or prejudice against people from other countries or cultures.";example="The rise in xenophobia led to calls for stricter border controls and anti-immigration policies.";category="Social Justice & Equity"},
@{word="Heteronormativity";meaning="The belief or assumption that heterosexuality is the normal, natural, and preferred sexual orientation for all people.";example="The children's book challenged heteronormativity by featuring a family with two mothers.";category="Social Justice & Equity"},
@{word="Cisnormativity";meaning="The assumption that all people identify with the gender they were assigned at birth, excluding transgender and non-binary identities.";example="Forms that only offer 'Male' and 'Female' checkboxes are examples of cisnormativity in data collection.";category="Social Justice & Equity"},
@{word="Colorism";meaning="Prejudice or discrimination against individuals with a dark skin tone, typically among people of the same ethnic or racial group.";example="Advertising campaigns that promote skin-whitening creams are criticized for encouraging colorism.";category="Social Justice & Equity"},
@{word="Social Stratification";meaning="The categorization of people into socio-economic tiers based on factors like wealth, income, race, education, and power.";example="The country's rigid social stratification made it extremely difficult for poor citizens to improve their lives.";category="Social Justice & Equity"},
@{word="Cultural Assimilation";meaning="The process by which a minority individual or group takes on the characteristics of a dominant culture, sometimes losing their original heritage.";example="Immigrants often face pressure of cultural assimilation, which can lead to the loss of their native language.";category="Social Justice & Equity"},
@{word="Economic Inequality";meaning="The unequal distribution of income, wealth, and economic opportunities between different individuals or groups in a society.";example="Tax reforms were proposed to reduce the growing economic inequality between the rich and the poor.";category="Social Justice & Equity"},
@{word="Environmental Racism";meaning="The practice of placing toxic waste sites, factories, or landfills near low-income or minority neighborhoods, harming their health.";example="Building a chemical plant near a low-income neighborhood is often cited as environmental racism.";category="Social Justice & Equity"},
@{word="Human Dignity";meaning="The basic belief that every person has an inherent right to respect and ethical treatment, which should never be violated.";example="Treating homeless individuals with kindness and respect is a way to honor their human dignity.";category="Social Justice & Equity"},
@{word="Civil Rights";meaning="The rights of citizens to political and social freedom and equality, protected by law against discrimination or infringement.";example="The historic march was a turning point in the struggle for civil rights and racial equality.";category="Social Justice & Equity"},
@{word="Structural Disadvantage";meaning="A disadvantage that is built into the rules and institutions of a society, making it harder for certain groups to succeed.";example="A lack of public transportation creates a structural disadvantage for residents seeking jobs in the city.";category="Social Justice & Equity"},
@{word="Social Mobility";meaning="The movement of individuals, families, or groups from one social or economic level to another in a society.";example="Access to affordable higher education is one of the most effective drivers of social mobility.";category="Social Justice & Equity"},
@{word="Generational Wealth";meaning="Financial assets, properties, or businesses that are passed down from one generation of a family to the next, often influenced by historical policies.";example="Homeownership is a primary way that families build and pass down generational wealth.";category="Social Justice & Equity"},
@{word="Digital Divide";meaning="The gap between those who have easy access to modern digital technology and the internet and those who do not.";example="During remote learning, the digital divide became clear when some students lacked internet access at home.";category="Social Justice & Equity"},
@{word="Cultural Competence";meaning="The ability to understand, appreciate, and interact effectively with people from cultures or belief systems different from one's own.";example="Nurses who develop cultural competence can provide better, more respectful care to diverse patients.";category="Cultural Empathy"},
@{word="Cultural Humility";meaning="A lifelong process of self-reflection and learning, where a person remains open to learning about other cultures without judging them.";example="Practicing cultural humility means listening to others and acknowledging that your own culture is not the only standard.";category="Cultural Empathy"},
@{word="Cultural Appropriation";meaning="The unacknowledged or inappropriate adoption of customs, practices, or ideas of one people or society by members of another, more dominant group.";example="Wearing a traditional native headdress as a fashion accessory is widely seen as cultural appropriation.";category="Cultural Empathy"},
@{word="Cultural Appreciation";meaning="The respectful study, learning, and sharing of elements of another culture to understand and honor its heritage.";example="Attending a traditional tea ceremony and learning about its history is a form of cultural appreciation.";category="Cultural Empathy"},
@{word="Implicit Bias";meaning="Thoughts, attitudes, or stereotypes that affect our understanding, actions, and decisions in an unconscious manner.";example="Even well-intentioned teachers may have an implicit bias that affects how they discipline different students.";category="Cultural Empathy"},
@{word="Ethnocentrism";meaning="The evaluation of other cultures according to preconceptions originating in the standards and customs of one's own culture.";example="Believing that your country's food and customs are superior to all others is an example of ethnocentrism.";category="Cultural Empathy"},
@{word="Stereotype Threat";meaning="A situational predicament where people are or feel themselves to be at risk of conforming to negative stereotypes about their social group.";example="Reminding girls of the stereotype that boys are better at math can trigger stereotype threat and lower their test scores.";category="Cultural Empathy"},
@{word="In-Group Bias";meaning="The tendency to favor, trust, and support members of one's own group or social circle over those from other groups.";example="The manager showed in-group bias by assigning the best projects to employees who attended his alma mater.";category="Cultural Empathy"},
@{word="Out-Group Bias";meaning="The tendency to view people outside one's own social group with suspicion, dislike, or unfair judgment.";example="We must be careful not to let out-group bias make us suspicious of new teams from other departments.";category="Cultural Empathy"},
@{word="Active Listening";meaning="A way of listening and responding to another person that improves mutual understanding and shows deep respect for their feelings.";example="Through active listening, the counselor made the student feel heard, respected, and understood.";category="Cultural Empathy"},
@{word="Empathy";meaning="The ability to understand and share the feelings of another person, putting oneself in their situation.";example="Showing empathy to a grieving friend means sitting with them and sharing their sadness.";category="Cultural Empathy"},
@{word="Self-Reflection";meaning="The careful thought and analysis of one's own beliefs, behaviors, and biases to learn and grow as a person.";example="Regular self-reflection helped him realize that his past comments had been insensitive to others.";category="Cultural Empathy"},
@{word="Unlearning";meaning="The deliberate process of letting go of old, biased, or incorrect assumptions and behaviors in order to adopt new, fairer perspectives.";example="Becoming an ally requires unlearning many of the societal stereotypes we grew up with.";category="Cultural Empathy"},
@{word="Ally";meaning="A person who makes a conscious commitment to support and stand up for a marginalized group, even if they are not a member of that group.";example="As an ally, she attended the rally to show solidarity with the disabled community.";category="Cultural Empathy"},
@{word="Cultural Empathy";meaning="The effort to understand and connect with the feelings, perspectives, and cultural experiences of someone from a different background.";example="Reading literature from diverse authors is a wonderful way to develop cultural empathy.";category="Cultural Empathy"},
@{word="Stereotyping";meaning="The practice of holding a simplified, generalized, and often incorrect belief about a whole group of people.";example="Assuming all older workers are bad with technology is an unfair form of stereotyping.";category="Cultural Empathy"},
@{word="Cross-Cultural Communication";meaning="The process of exchanging information, ideas, and feelings between people from different cultural backgrounds.";example="Clear cross-cultural communication is vital for the success of multinational business negotiations.";category="Cultural Empathy"},
@{word="Inclusive Dialogue";meaning="A conversation where everyone's voice is welcomed and participants work together to understand each other's perspectives.";example="The town hall meeting fostered an inclusive dialogue between city planners and local residents.";category="Cultural Empathy"},
@{word="Intercultural Sensitivity";meaning="The ability to recognize, respect, and value cultural differences in communication and behavior.";example="Living abroad for a year helped her develop a deep intercultural sensitivity and respect for differences.";category="Cultural Empathy"},
@{word="Mutual Respect";meaning="The agreement between two or more people to value and honor each other's opinions, backgrounds, and human dignity.";example="A successful marriage is built on a foundation of trust, communication, and mutual respect.";category="Cultural Empathy"},
@{word="Perspective-Taking";meaning="The process of viewing a situation or understanding a concept from an alternative point of view, such as that of another person or group.";example="Perspective-taking allows us to understand why a customer might be frustrated with our service.";category="Cultural Empathy"},
@{word="Self-Awareness";meaning="The conscious knowledge of one's own character, feelings, motives, desires, and personal biases.";example="Developing self-awareness helps leaders understand how their emotions and actions affect their team.";category="Cultural Empathy"},
@{word="Social Belonging";meaning="The human need to be accepted as a member of a social group and to feel connected to others in a community.";example="Creating student clubs helps freshman feel a sense of social belonging during their first semester.";category="Cultural Empathy"},
@{word="Inclusiveness";meaning="The quality of including and treating all kinds of people fairly and equally, ensuring no one is left out.";example="The festival organizers prioritized inclusiveness by providing sign language interpreters for all performances.";category="Cultural Empathy"},
@{word="Common Ground";meaning="A shared area of agreement, interest, or belief found between people who have different opinions or cultural backgrounds.";example="Despite their different backgrounds, the parents found common ground in wanting the best education for their kids.";category="Cultural Empathy"}
)

$deiJson = $dei | ConvertTo-Json -Depth 5
Set-Content -Path "$batchDir\v6_diversity_inclusion.json" -Value $deiJson -Encoding UTF8
Write-Host "✅ v6_diversity_inclusion.json written with $($dei.Count) entries."

# =====================================================================
# 2. ENVIRONMENTAL SUSTAINABILITY VOCABULARY
# =====================================================================

$eco = @(
@{word="Biodiversity";meaning="The variety of all living things, including plants, animals, and microorganisms, in a particular area or ecosystem.";example="Protecting rain forests is crucial because they contain most of the world's biodiversity.";category="Conservation"},
@{word="Reforestation";meaning="The process of planting new trees in an area where a forest has been cut down or destroyed.";example="Community volunteers organized a reforestation project to plant one thousand native oak trees.";category="Conservation"},
@{word="Ecosystem";meaning="A community of living organisms interacting with each other and their non-living physical environment.";example="A single pond is a small ecosystem where frogs, insects, fish, and plants rely on one another.";category="Conservation"},
@{word="Wildlife Corridor";meaning="A strip of natural habitat that connects different wildlife populations separated by human structures like roads or cities.";example="The highway overpass acts as a wildlife corridor, allowing deer and bears to cross safely.";category="Conservation"},
@{word="Habitat Loss";meaning="The destruction or damage of the natural environments where plants and animals live, usually caused by human activity.";example="Urban expansion is the leading cause of habitat loss for many local bird species.";category="Conservation"},
@{word="Endangered Species";meaning="A species of animal or plant that is in danger of dying out and becoming extinct.";example="The giant panda was once a famous endangered species, but conservation efforts have helped its numbers grow.";category="Conservation"},
@{word="Ecological Balance";meaning="A stable state of equilibrium in an ecosystem where all living things live in harmony without one species dominating.";example="Reintroducing wolves helped restore the ecological balance by controlling the deer population.";category="Conservation"},
@{word="Rewilding";meaning="The practice of restoring land to its natural, wild state, especially by reintroducing native animals.";example="The rewilding of the valley allowed native flowers, birds, and small mammals to return.";category="Conservation"},
@{word="Deforestation";meaning="The large-scale cutting down or clearing of forests, typically to make space for farming or building.";example="Deforestation in the Amazon contributes significantly to global carbon emissions.";category="Conservation"},
@{word="Overfishing";meaning="Catching fish at a faster rate than they can naturally reproduce, leading to a dangerous decrease in fish populations.";example="Overfishing in the North Sea has forced the government to set strict limits on fishing boats.";category="Conservation"},
@{word="Marine Protected Area";meaning="A designated region of the ocean where human activities are limited to protect sealife and habitats.";example="Fishing and oil drilling are strictly banned inside the new marine protected area.";category="Conservation"},
@{word="Coral Bleaching";meaning="The process where corals turn white and weaken because ocean waters are too warm, forcing out the colorful algae that feed them.";example="Rising ocean temperatures have caused severe coral bleaching across the Great Barrier Reef.";category="Conservation"},
@{word="Desertification";meaning="The process by which fertile, healthy land turns into dry desert, often due to climate change or bad farming practices.";example="Overuse of water resources has accelerated the desertification of once-green regions.";category="Conservation"},
@{word="Wetland Restoration";meaning="Rehabilitating damaged swamps, marshes, or bogs so they can naturally filter water and provide homes for wildlife again.";example="The wetland restoration project successfully brought back clean water and nesting birds to the area.";category="Conservation"},
@{word="Conservationist";meaning="A person who actively works to protect and preserve the environment, plants, animals, and natural resources.";example="The conservationist gave a talk at our school about how we can save water at home.";category="Conservation"},
@{word="Natural Reserve";meaning="An area of land set aside and protected by the government or organizations to keep plants and animals safe.";example="We hiked through the natural reserve, making sure not to disturb the nesting birds.";category="Conservation"},
@{word="Invasive Species";meaning="A plant, animal, or insect that is brought to a new place where it does not belong and causes harm to native species.";example="The Kudzu vine is an invasive species in North America that grows rapidly and smothers local trees.";category="Conservation"},
@{word="Ecological Footprint";meaning="A measurement of how much land and water area a single person or group requires to produce the resources they consume.";example="Using public transit instead of driving a personal car helps reduce your individual ecological footprint.";category="Conservation"},
@{word="Biosphere";meaning="The parts of the Earth's surface, atmosphere, and oceans where living organisms exist.";example="All ecosystems on Earth combine to form the giant global system called the biosphere.";category="Conservation"},
@{word="Carbon Sequestration";meaning="The natural or artificial process of capturing and storing carbon dioxide from the atmosphere to help reduce global warming.";example="Forests are excellent for carbon sequestration because trees absorb carbon dioxide as they grow.";category="Conservation"},
@{word="Soil Erosion";meaning="The wearing away and loss of the top layer of soil, usually caused by wind, rain, or farming activities.";example="Planting grass on hillsides helps prevent soil erosion by holding the dirt in place with roots.";category="Conservation"},
@{word="Sustainable Forestry";meaning="Managing forests in a way that harvests wood but ensures the forest survives and new trees grow back.";example="The paper company practices sustainable forestry by planting two trees for every one they cut down.";category="Conservation"},
@{word="Canopy";meaning="The high, thick layer of leaves and branches formed by the tops of trees in a forest, which shades the ground below.";example="Monkeys and colorful birds spend most of their lives high up in the rainforest canopy.";category="Conservation"},
@{word="Watershed";meaning="An area of land where all the rain and melting snow drains into a single river, lake, or ocean.";example="Protecting the watershed ensures that the drinking water for the nearby town remains clean.";category="Conservation"},
@{word="Keystone Species";meaning="A species that has an exceptionally large effect on its ecosystem, and whose removal would cause the system to collapse.";example="Sea otters are a keystone species because they eat sea urchins, protecting kelp forests from being destroyed.";category="Conservation"},
@{word="Overgrazing";meaning="Allowing farm animals to eat grass so heavily that the plants cannot grow back, damaging the soil.";example="Overgrazing by cattle turned the fertile grassland into a dry, dusty field.";category="Conservation"},
@{word="Fauna";meaning="All the animal life present in a particular area, time period, or environment.";example="We studied the unique desert fauna, which includes lizards, snakes, and desert foxes.";category="Conservation"},
@{word="Flora";meaning="All the plant life present in a particular area, time period, or environment.";example="The damp volcanic soil supports a rich variety of tropical flora.";category="Conservation"},
@{word="Land Conservation";meaning="The effort to protect open spaces, forests, and wild lands from being developed by builders and industries.";example="The local land conservation group bought the farm to keep it from being turned into a shopping mall.";category="Conservation"},
@{word="Eco-Tourism";meaning="Responsible travel to natural areas that protects the environment and supports the local people.";example="The eco-tourism resort uses solar power, harvests rainwater, and employs local guides.";category="Conservation"},
@{word="Renewable Energy";meaning="Energy made from natural sources that never run out, such as sunlight, wind, and water.";example="Switching to renewable energy is the most effective way to combat climate change.";category="Renewable Resources"},
@{word="Solar Energy";meaning="Power generated by capturing light and heat from the sun and turning it into electricity.";example="Installing panels on your roof allows you to use solar energy to power your home appliances.";category="Renewable Resources"},
@{word="Wind Power";meaning="Electricity created by using wind turbines to capture the energy of moving air.";example="Wind power is growing rapidly as huge turbines are built in windy coastal areas.";category="Renewable Resources"},
@{word="Geothermal Energy";meaning="Heat energy that comes from deep inside the Earth, used to generate electricity or heat buildings.";example="Iceland uses geothermal energy from volcanic hot rocks to heat almost all of its homes.";category="Renewable Resources"},
@{word="Hydroelectric Power";meaning="Electricity produced by using the force of flowing or falling water to spin generator turbines.";example="The massive river dam generates enough hydroelectric power to supply the entire state.";category="Renewable Resources"},
@{word="Biomass";meaning="Organic materials, like wood, plants, and agricultural waste, that are burned to create heat or electricity.";example="Using agricultural leftovers as biomass helps generate energy from things we would otherwise throw away.";category="Renewable Resources"},
@{word="Photovoltaic Cell";meaning="A tiny solar device that converts sunlight directly into electrical energy.";example="Each solar panel is made of dozens of photovoltaic cells working together to absorb light.";category="Renewable Resources"},
@{word="Tidal Energy";meaning="Energy created by the natural rise and fall of ocean tides, which spins underwater turbines.";example="Unlike solar power, tidal energy is highly predictable because the ocean tides follow a strict daily schedule.";category="Renewable Resources"},
@{word="Biofuel";meaning="A liquid fuel made from organic materials, such as corn, sugar cane, or vegetable oils.";example="Some city buses run on biofuel made from recycled cooking oils to reduce air pollution.";category="Renewable Resources"},
@{word="Smart Grid";meaning="A modern electrical system that uses digital technology to deliver electricity efficiently and reliably.";example="A smart grid can automatically detect power cuts and route electricity to where it is needed most.";category="Renewable Resources"},
@{word="Off-Grid";meaning="Living without being connected to public utilities like the electricity, gas, and water systems.";example="They bought a cabin in the mountains and lived off-grid using solar panels and a private well.";category="Renewable Resources"},
@{word="Wind Farm";meaning="A large area of land or sea covered with many wind turbines used to generate commercial electricity.";example="The offshore wind farm was built in the ocean where wind blows steadily all day.";category="Renewable Resources"},
@{word="Wave Energy";meaning="Electricity generated by capturing the movement of surface waves on the ocean.";example="Engineers are testing new floating devices designed to convert wave energy into electricity.";category="Renewable Resources"},
@{word="Renewable Resource";meaning="A natural resource that can replenish itself naturally over a short period, such as trees, water, and sunlight.";example="Bamboo is a highly renewable resource because it can grow up to three feet in just one day.";category="Renewable Resources"},
@{word="Non-Renewable";meaning="Resources that exist in limited amounts and cannot be replaced once they are completely used up, such as coal, oil, and gas.";example="Fossil fuels are non-renewable resources that took millions of years to form under the ground.";category="Renewable Resources"},
@{word="Clean Energy";meaning="Energy sources that generate electricity without releasing harmful greenhouse gases or air pollutants.";example="The government is offering tax breaks to businesses that invest in clean energy projects.";category="Renewable Resources"},
@{word="Net Metering";meaning="A system that allows solar panel owners to sell their excess electricity back to the public power company.";example="Thanks to net metering, our electricity bill was actually negative during the sunny summer months.";category="Renewable Resources"},
@{word="Turbine";meaning="A machine with blades that are spun by wind, water, or steam to turn a generator and produce electricity.";example="A single modern wind turbine can generate enough power for hundreds of households.";category="Renewable Resources"},
@{word="Hybrid Vehicle";meaning="A car that has both a traditional gasoline engine and a rechargeable electric motor to improve fuel efficiency.";example="Driving a hybrid vehicle helps you save money on gasoline while producing fewer emissions.";category="Renewable Resources"},
@{word="Electric Vehicle";meaning="A car that runs entirely on electricity stored in rechargeable batteries and produces zero direct exhaust emissions.";example="As battery technology improves, electric vehicles are becoming more affordable for average drivers.";category="Renewable Resources"},
@{word="Hydrogen Fuel Cell";meaning="A device that combines hydrogen gas and oxygen to generate electricity, producing only harmless water vapor as exhaust.";example="Hydrogen fuel cells are being developed to power heavy vehicles like trucks and buses.";category="Renewable Resources"},
@{word="Green Living";meaning="A lifestyle where individuals try to reduce their environmental impact and conserve natural resources.";example="Green living involves recycling, saving energy, eating local food, and reducing plastic use.";category="Eco-friendly Practices"},
@{word="Biodegradable";meaning="Capable of being broken down naturally by bacteria or fungi into harmless substances over time.";example="These biodegradable plates are made from sugarcane fiber and will decompose in a few weeks.";category="Eco-friendly Practices"},
@{word="Compost";meaning="Decayed organic matter, like food scraps and leaves, that is recycled as a rich fertilizer for garden soil.";example="Instead of throwing away banana peels and coffee grounds, we put them in the compost bin.";category="Eco-friendly Practices"},
@{word="Zero Waste";meaning="A lifestyle where a person avoids creating any trash that goes to a landfill, prioritizing reuse and recycling.";example="To practice zero waste, she buys grains in bulk using her own glass jars.";category="Eco-friendly Practices"},
@{word="Upcycling";meaning="Turning old, discarded items or waste materials into new products of higher quality, beauty, or usefulness.";example="She turned an old wooden ladder into a beautiful bookshelf, a perfect example of upcycling.";category="Eco-friendly Practices"},
@{word="Single-Use Plastic";meaning="Plastic items designed to be used only once and then thrown away, such as shopping bags, straws, and water bottles.";example="Many cities have banned single-use plastic bags to protect oceans and marine life.";category="Eco-friendly Practices"},
@{word="Conscious Consumerism";meaning="Buying goods and services that are produced in an environmentally friendly and socially responsible way.";example="Conscious consumerism encourages people to support brands that treat workers fairly and use organic cotton.";category="Eco-friendly Practices"},
@{word="Recycling";meaning="The process of collecting and processing waste materials to turn them into new materials and products.";example="Always rinse out plastic bottles before putting them in the recycling bin.";category="Eco-friendly Practices"},
@{word="Organic Farming";meaning="Growing crops and raising animals without using artificial chemical fertilizers, pesticides, or genetically modified seeds.";example="Organic farming keeps the soil healthy and prevents chemical runoff from entering local rivers.";category="Eco-friendly Practices"},
@{word="Permaculture";meaning="An agricultural design system that mimics natural ecosystems to grow food and live sustainably.";example="By practicing permaculture, they created a self-sustaining forest garden that produces fruits and nuts.";category="Eco-friendly Practices"},
@{word="Greywater";meaning="Wastewater from household sinks, showers, and washing machines that can be safely reused to water plants.";example="The family installed a greywater system to reuse laundry water on their backyard fruit trees.";category="Eco-friendly Practices"},
@{word="Rainwater Harvesting";meaning="Collecting and storing rainwater from roofs to use later for watering plants or flushing toilets.";example="Rainwater harvesting is a life-saving practice in areas that experience long droughts.";category="Eco-friendly Practices"},
@{word="Greenwashing";meaning="The practice of making a company or product seem more environmentally friendly than it actually is.";example="The soda company was accused of greenwashing when they advertised their plastic bottles as eco-friendly.";category="Eco-friendly Practices"},
@{word="Plant-Based Diet";meaning="A diet consisting mostly of foods derived from plants, such as vegetables, grains, nuts, and fruits.";example="Following a plant-based diet helps reduce carbon emissions, as meat production requires vast land and water.";category="Eco-friendly Practices"},
@{word="Locally Sourced";meaning="Products or food grown or manufactured in the nearby area rather than shipped from far away.";example="The restaurant serves locally sourced vegetables purchased from farmers down the road.";category="Eco-friendly Practices"},
@{word="Food Miles";meaning="The distance food travels from the farm where it is produced to the table where it is eaten by consumers.";example="Buying imported strawberries in winter increases your food miles and environmental impact.";category="Eco-friendly Practices"},
@{word="Fast Fashion";meaning="Inexpensive clothing produced rapidly in response to the latest trends, leading to excessive waste and pollution.";example="Fast fashion brands encourage people to buy new clothes constantly, resulting in mountains of textile waste.";category="Eco-friendly Practices"},
@{word="Slow Fashion";meaning="An eco-friendly movement that encourages buying high-quality, durable clothes made ethically and sustainably.";example="Investing in classic pieces from slow fashion labels means your clothes will last for many years.";category="Eco-friendly Practices"},
@{word="Phantom Load";meaning="The electricity wasted by household appliances when they are plugged in but turned off or in standby mode.";example="Unplugging your television and microwave when going on vacation eliminates the phantom load.";category="Eco-friendly Practices"},
@{word="Eco-Label";meaning="An official mark placed on a product certifying that it meets specific environmental standards.";example="The eco-label on the dish soap shows that it is biodegradable and non-toxic to fish.";category="Eco-friendly Practices"},
@{word="Drought-Tolerant";meaning="Plants that can survive and grow with very little water or rainfall.";example="We replaced our grassy lawn with drought-tolerant lavender and native desert plants to save water.";category="Eco-friendly Practices"},
@{word="Microplastics";meaning="Extremely tiny pieces of plastic, less than five millimeters long, that pollute waters and harm aquatic wildlife.";example="Microplastics have been found inside fish, showing how plastic pollution enters the global food chain.";category="Eco-friendly Practices"},
@{word="Minimalism";meaning="A lifestyle choice centered around reducing possessions and focusing on simple, conscious consumption.";example="Adopting minimalism helped him realize he did not need to buy new gadgets to be happy.";category="Eco-friendly Practices"},
@{word="Circular Economy";meaning="An economic model focused on designing out waste, sharing, repairing, reusing, and recycling materials continuously.";example="In a circular economy, smartphone parts are recovered at the end of their life to make new phones.";category="Sustainability Logistics"},
@{word="Carbon Footprint";meaning="The total amount of greenhouse gases produced directly and indirectly by an individual, organization, or product.";example="Eating less beef and taking public transit are simple ways to lower your carbon footprint.";category="Sustainability Logistics"},
@{word="Carbon Offset";meaning="Paying to support projects that reduce or absorb carbon dioxide to compensate for emissions you have produced.";example="The airline offers a carbon offset option where passengers can pay extra to plant trees.";category="Sustainability Logistics"},
@{word="Net-Zero";meaning="A state where the amount of greenhouse gas emitted into the atmosphere is equal to the amount removed.";example="The city has pledged to reach net-zero carbon emissions by the year twenty-fifty.";category="Sustainability Logistics"},
@{word="Carbon Tax";meaning="A fee imposed by governments on fossil fuels, designed to encourage companies to reduce their greenhouse gas emissions.";example="Supporters believe a carbon tax will make renewable energy more competitive than coal and oil.";category="Sustainability Logistics"},
@{word="Cap-and-Trade";meaning="A government system that sets a maximum limit on pollution and allows companies to buy and sell pollution permits.";example="Under the cap-and-trade system, clean companies can sell their unused permits to heavy polluters.";category="Sustainability Logistics"},
@{word="Cradle-to-Cradle";meaning="A product design concept where materials are recycled or composted completely, leaving absolutely no waste.";example="The office chair was designed cradle-to-cradle, meaning every single part can be safely recycled.";category="Sustainability Logistics"},
@{word="Urban Sprawl";meaning="The rapid and uncontrolled spread of cities and suburbs into nearby rural areas and natural habitats.";example="Urban sprawl increases traffic congestion because residents must drive long distances to work.";category="Sustainability Logistics"},
@{word="Green Belt";meaning="An area of protected open land surrounding a city where building and development are strictly prohibited.";example="The green belt protects forests from developers and provides city residents with clean air.";category="Sustainability Logistics"},
@{word="Public Transit";meaning="Shared transportation services like buses, trains, and subways that carry large numbers of passengers.";example="Improving public transit encourages people to leave their cars at home, reducing urban smog.";category="Sustainability Logistics"},
@{word="Green Roof";meaning="A roof of a building that is covered with soil and living plants, which insulates and reduces rainwater runoff.";example="The new city hall features a green roof that keeps the building cool in summer and absorbs heavy rain.";category="Sustainability Logistics"},
@{word="Passive House";meaning="An extremely high standard for building energy efficiency, requiring very little heating or cooling.";example="Because it is so well insulated, a passive house uses ninety percent less heating energy than standard homes.";category="Sustainability Logistics"},
@{word="Carpooling";meaning="An arrangement where several people share a single car ride to work or school to save fuel and cut emissions.";example="Carpooling with colleagues allows us to use the high-occupancy vehicle lanes and get to work faster.";category="Sustainability Logistics"},
@{word="Urban Farming";meaning="The practice of growing food, raising animals, and producing crops inside or near crowded city areas.";example="Urban farming on rooftop plots provides fresh, organic salads to local city neighborhoods.";category="Sustainability Logistics"},
@{word="Sustainable Development";meaning="Economic growth that meets our current needs without hurting the ability of future generations to meet their own needs.";example="Sustainable development balances industrial growth with forest conservation and clean energy.";category="Sustainability Logistics"},
@{word="Climate Refugee";meaning="A person who is forced to flee their home due to severe environmental changes like rising sea levels or extreme droughts.";example="As sea levels rise, thousands of island residents risk becoming climate refugees.";category="Sustainability Logistics"},
@{word="Paris Agreement";meaning="A major international treaty signed in twenty-fifteen where countries pledged to limit global warming.";example="Under the Paris Agreement, nations set targets to reduce greenhouse gases and transition to clean energy.";category="Sustainability Logistics"},
@{word="Green Infrastructure";meaning="A network of natural areas like parks, wetlands, and tree-lined streets designed to manage water and improve urban air.";example="Investing in green infrastructure helps cities manage floodwaters naturally instead of relying solely on concrete pipes.";category="Sustainability Logistics"},
@{word="Environmental Justice";meaning="The fair treatment and involvement of all people in environmental laws, ensuring no group suffers undue pollution.";example="Environmental justice activists fight to keep dangerous chemical plants out of low-income neighborhoods.";category="Sustainability Logistics"},
@{word="Regenerative Agriculture";meaning="A farming method that restores soil health, increases biodiversity, and captures carbon dioxide in the ground.";example="By practicing regenerative agriculture, the farm has improved crop yields while bringing back local wildlife.";category="Sustainability Logistics"},
@{word="Landfill Diversion";meaning="The practice of redirecting waste away from landfills through recycling, composting, or repairing.";example="The city achieved an eighty percent landfill diversion rate by implementing mandatory food waste composting.";category="Sustainability Logistics"},
@{word="Sustainable Packaging";meaning="Product containers designed with minimal environmental impact, using recycled, compostable, or easily reusable materials.";example="The cosmetics brand switched to sustainable packaging made from plant fibers that dissolve in water.";category="Sustainability Logistics"},
@{word="Extended Producer Responsibility";meaning="A policy requiring manufacturers to pay for and manage the collection and recycling of their products after consumers are done with them.";example="Extended producer responsibility laws force electronics companies to set up free recycling centers for old TVs.";category="Sustainability Logistics"}
)

$ecoJson = $eco | ConvertTo-Json -Depth 5
Set-Content -Path "$batchDir\v6_environmental_sustainability.json" -Value $ecoJson -Encoding UTF8
Write-Host "✅ v6_environmental_sustainability.json written with $($eco.Count) entries."

Write-Host ""
Write-Host "🎉 Both missing JSON files have been written successfully!"
